CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TABLE "FamilyTree" ("id" UUID NOT NULL DEFAULT gen_random_uuid(),"name" TEXT NOT NULL,"backgroundStyle" TEXT NOT NULL DEFAULT 'botanical',"backgroundColor" TEXT NOT NULL DEFAULT '#faf9f3',"treeColor" TEXT NOT NULL DEFAULT '#76927b',"accentColor" TEXT NOT NULL DEFAULT '#d7a74c',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "FamilyTree_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Person" ("id" UUID NOT NULL DEFAULT gen_random_uuid(),"treeId" UUID NOT NULL,"name" TEXT NOT NULL,"birthDate" TIMESTAMP(3),"deathDate" TIMESTAMP(3),"bio" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Person_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ParentRelationship" ("id" UUID NOT NULL DEFAULT gen_random_uuid(),"treeId" UUID NOT NULL,"parentId" UUID NOT NULL,"childId" UUID NOT NULL,"type" TEXT NOT NULL DEFAULT 'biological',CONSTRAINT "ParentRelationship_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Partnership" ("id" UUID NOT NULL DEFAULT gen_random_uuid(),"treeId" UUID NOT NULL,"partnerAId" UUID NOT NULL,"partnerBId" UUID NOT NULL,"status" TEXT NOT NULL DEFAULT 'partnered',"marriageDate" TIMESTAMP(3),CONSTRAINT "Partnership_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SiblingRelationship" ("id" UUID NOT NULL DEFAULT gen_random_uuid(),"treeId" UUID NOT NULL,"siblingAId" UUID NOT NULL,"siblingBId" UUID NOT NULL,"type" TEXT NOT NULL DEFAULT 'sibling',CONSTRAINT "SiblingRelationship_pkey" PRIMARY KEY ("id"));
CREATE INDEX "Person_treeId_idx" ON "Person"("treeId"); CREATE INDEX "ParentRelationship_treeId_idx" ON "ParentRelationship"("treeId"); CREATE INDEX "Partnership_treeId_idx" ON "Partnership"("treeId"); CREATE INDEX "SiblingRelationship_treeId_idx" ON "SiblingRelationship"("treeId");
CREATE UNIQUE INDEX "ParentRelationship_parentId_childId_key" ON "ParentRelationship"("parentId","childId"); CREATE UNIQUE INDEX "Partnership_partnerAId_partnerBId_key" ON "Partnership"("partnerAId","partnerBId"); CREATE UNIQUE INDEX "SiblingRelationship_siblingAId_siblingBId_key" ON "SiblingRelationship"("siblingAId","siblingBId");
ALTER TABLE "Person" ADD CONSTRAINT "Person_treeId_fkey" FOREIGN KEY ("treeId") REFERENCES "FamilyTree"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ParentRelationship" ADD CONSTRAINT "ParentRelationship_treeId_fkey" FOREIGN KEY ("treeId") REFERENCES "FamilyTree"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Partnership" ADD CONSTRAINT "Partnership_treeId_fkey" FOREIGN KEY ("treeId") REFERENCES "FamilyTree"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "SiblingRelationship" ADD CONSTRAINT "SiblingRelationship_treeId_fkey" FOREIGN KEY ("treeId") REFERENCES "FamilyTree"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ParentRelationship" ADD CONSTRAINT "ParentRelationship_parentId_fkey" FOREIGN KEY ("parentId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "ParentRelationship" ADD CONSTRAINT "ParentRelationship_childId_fkey" FOREIGN KEY ("childId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Partnership" ADD CONSTRAINT "Partnership_partnerAId_fkey" FOREIGN KEY ("partnerAId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Partnership" ADD CONSTRAINT "Partnership_partnerBId_fkey" FOREIGN KEY ("partnerBId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "SiblingRelationship" ADD CONSTRAINT "SiblingRelationship_siblingAId_fkey" FOREIGN KEY ("siblingAId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "SiblingRelationship" ADD CONSTRAINT "SiblingRelationship_siblingBId_fkey" FOREIGN KEY ("siblingBId") REFERENCES "Person"("id") ON DELETE CASCADE ON UPDATE CASCADE;
